const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

// In-memory storage for simplicity, replace with a database in production
let levelsCompleted = {};

app.post('/complete-level', (req, res) => {
    const levelId = req.body.level_id;
    const score = req.body.score;
    const time = req.body.time;

    if (!levelsCompleted[levelId]) {
        levelsCompleted[levelId] = { attempts: 0, score: 0, time: 0 };
    }

    levelsCompleted[levelId].attempts++;
    levelsCompleted[levelId].score += score;
    levelsCompleted[levelId].time += time;

    const rewardLevel = Math.floor(Math.random() * 5) + 1; // Randomly award a level between 1 and 5
    const rewardScore = Math.floor(Math.random() * 1000); // Randomly award a score between 0 and 999

    res.json({
        reward_level: rewardLevel,
        reward_score: rewardScore
    });
});

app.post('/claim-reward', (req, res) => {
    const levelId = req.body.level_id;
    const rewardLevel = levelsCompleted[levelId].reward_level || 1; // Default to level 1 if not set
    const rewardScore = levelsCompleted[levelId].reward_score || 0; // Default to score 0 if not set

    res.json({
        reward_level: rewardLevel,
        reward_score: rewardScore
    });
});

app.listen(3000, () => {
    console.log('Server listening on port 3000');
});